# phase_01_dataset_analysis.py
# purpose: analyze reasoning dataset generated by symbolic engine

import pandas as pd


class DatasetAnalyzerV1:
    def __init__(self, path="results/phase_01_taxonomy/results.csv"):
        self.path = path
        self.df = pd.read_csv(path)

    def basic_stats(self):
        total = len(self.df)
        yes = len(self.df[self.df["answer"] == "yes"])
        no = total - yes

        return {
            "total_samples": total,
            "yes_rate": yes / total,
            "no_rate": no / total
        }

    def failure_analysis(self):
        failures = self.df[self.df["reasoning_path"].isna()]

        return {
            "unreachable_queries": len(failures),
            "unreachable_rate": len(failures) / len(self.df)
        }

    def hop_analysis(self):
        return {
            "avg_hops": self.df["hops"].mean(),
            "max_hops": self.df["hops"].max(),
            "min_hops": self.df["hops"].min()
        }

    def category_insight(self):
        # simple heuristic: longer chains = deeper reasoning
        deep = self.df[self.df["hops"] >= 3]
        shallow = self.df[self.df["hops"] < 3]

        return {
            "deep_reasoning_cases": len(deep),
            "shallow_reasoning_cases": len(shallow)
        }

    def run_all(self):
        print("\n=== basic stats ===")
        print(self.basic_stats())

        print("\n=== failure analysis ===")
        print(self.failure_analysis())

        print("\n=== hop analysis ===")
        print(self.hop_analysis())

        print("\n=== depth ===")
        print(self.category_insight())


if __name__ == "__main__":
    analyzer = DatasetAnalyzerV1()
    analyzer.run_all()